    let mut state = State::new();
    let mut case = CaseReport {
        name,
        ok: true,
        decisions: Vec::new(),
        stale: Vec::new(),
    };
    for event in events {
        phase_a(&mut state, &event, &mut case)?;
    }
    case.ok = case.stale.is_empty();
    Ok(case)
